const p = $input.item.json;
return {
  json: {
    praia_id: Number(p.id),
    praia_nome: String(p.nome),
    praia_latitude: Number(p.latitude),
    praia_longitude: Number(p.longitude),
    textQuery: `${p.nome} ${p.concelho ?? ''} Portugal`
  }
};

// Process all merged items in one pass.
function haversine(lat1, lon1, lat2, lon2) {
  const R = 6371;
  const dLat = (lat2 - lat1) * Math.PI / 180;
  const dLon = (lon2 - lon1) * Math.PI / 180;
  const a = Math.sin(dLat / 2) ** 2 +
            Math.cos(lat1 * Math.PI / 180) * Math.cos(lat2 * Math.PI / 180) *
            Math.sin(dLon / 2) ** 2;
  return R * 2 * Math.atan2(Math.sqrt(a), Math.sqrt(1 - a));
}

// Strip accents, lowercase, drop punctuation
function normalize(s) {
  return String(s ?? '')
    .toLowerCase()
    .normalize('NFD').replace(/[\u0300-\u036f]/g, '')
    .replace(/[^a-z0-9\s]/g, ' ')
    .replace(/\s+/g, ' ')
    .trim();
}

// Generic words to ignore when comparing beach names to place names
const STOPWORDS = new Set([
  'praia', 'praias', 'beach', 'plage',
  'norte', 'sul', 'centro', 'este', 'oeste', 'nascente', 'poente', 'leste',
  'faja', 'cabo', 'porto', 'novo', 'nova', 'velho', 'velha', 'grande', 'pequena'
]);

function significantTokens(s) {
  return normalize(s).split(' ').filter(t => t.length >= 4 && !STOPWORDS.has(t));
}

const out = [];
let rejectedDist = 0, rejectedName = 0, accepted = 0;

for (const inp of $input.all()) {
  const item = inp.json ?? {};
  const nomePraia = String(item.praia_nome ?? 'unknown');

  if (item.error) {
    console.log(`${nomePraia}: API error — ${item.error.message ?? JSON.stringify(item.error)}`);
    continue;
  }

  const places = Array.isArray(item.places) ? item.places : [];
  if (places.length === 0) continue;

  const place = places[0];
  if (!place || typeof place !== 'object') continue;

  const lat2 = place.location?.latitude;
  const lon2 = place.location?.longitude;
  if (typeof lat2 !== 'number' || typeof lon2 !== 'number') continue;

  const lat1 = Number(item.praia_latitude);
  const lon1 = Number(item.praia_longitude);
  if (!isFinite(lat1) || !isFinite(lon1)) continue;

  const dist = haversine(lat1, lon1, lat2, lon2);
  const displayName = place.displayName?.text ?? '';

  // Name-overlap check: at least one significant token from beach name must appear in displayName
  const beachTokens = significantTokens(nomePraia);
  const placeNorm = normalize(displayName);
  const overlap = beachTokens.filter(t => placeNorm.includes(t));
  const nameOK = beachTokens.length === 0 || overlap.length > 0;

  console.log(`${nomePraia} -> ${displayName}: ${dist.toFixed(2)} km, tokens=[${beachTokens.join(',')}], overlap=[${overlap.join(',')}]`);

  if (dist > 5.0) {
    console.log(`  REJECTED (distance > 5km)`);
    rejectedDist++;
    continue;
  }

  if (!nameOK) {
    console.log(`  REJECTED (no name overlap)`);
    rejectedName++;
    continue;
  }

  const placeId = String(place.id ?? '');
  if (!placeId) continue;

  console.log(`  MATCHED`);
  accepted++;
  out.push({
    json: {
      id: Number(item.praia_id),
      google_place_id: placeId,
      google_rating: place.rating == null ? null : Number(place.rating),
      google_review_count: place.userRatingCount == null ? null : Number(place.userRatingCount)
    }
  });
}

console.log(`Validar e Filtrar: ${accepted} matched, ${rejectedDist} rejected (distance), ${rejectedName} rejected (name) of ${$input.all().length} candidates`);
return out;

const matches = $input.all().map(i => i.json);
console.log(`Building SQL UPDATE for ${matches.length} matched beaches`);

if (matches.length === 0) {
  console.log('No matches found — nothing to update');
  return [];
}

const sqlNullable = (v) => v == null ? 'NULL' : String(v);

const values = matches
  .map(m => `(${m.id}, '${m.google_place_id.replace(/'/g, "''")}'::text, ${sqlNullable(m.google_rating)}::numeric, ${sqlNullable(m.google_review_count)}::integer)`)
  .join(',\n');

const sql = `
UPDATE praias
SET google_place_id = v.place_id,
    google_rating = v.rating,
    google_review_count = v.review_count
FROM (VALUES ${values}) AS v(id, place_id, rating, review_count)
WHERE praias.id = v.id::integer
`;

return [{ json: { sql, total: matches.length } }];
